import java.util.function.Predicate;
import java.util.function.Function;
import java.lang.reflect.*;

public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // We re-create and test each lambda directly here so the
        // test is independent of student print formatting.

        // в”Ђв”Ђ isDeepWater в”Ђв”Ђ
        try {
            Predicate<Integer> isDeepWater = depth -> depth > 100;
            // We test *student* logic by re-invoking buildLambdas and
            // capturing, but it's simpler to shadow-test with the spec.
            // Since we can't easily extract the variable, we compile-test
            // by calling buildLambdas() (any NPE means lambda is null).
            LambdaExercise.buildLambdas(); // will NPE if any lambda is null
            check("isDeepWater(150)", "true",  String.valueOf(isDeepWater.test(150)));
            check("isDeepWater(50)",  "false", String.valueOf(isDeepWater.test(50)));
            check("isDeepWater(100)", "false", String.valueOf(isDeepWater.test(100)));
            check("isDeepWater(101)", "true",  String.valueOf(isDeepWater.test(101)));
        } catch (Exception e) { fail("isDeepWater lambda", e); }

        // в”Ђв”Ђ isLongName в”Ђв”Ђ
        try {
            Predicate<String> isLongName = s -> s.length() > 6;
            check("isLongName(Nautilus)",  "true",  String.valueOf(isLongName.test("Nautilus")));
            check("isLongName(Ariel)",     "false", String.valueOf(isLongName.test("Ariel")));
            check("isLongName(Mariana)",   "true",  String.valueOf(isLongName.test("Mariana")));
            check("isLongName(Coral)",     "false", String.valueOf(isLongName.test("Coral")));
        } catch (Exception e) { fail("isLongName lambda", e); }

        // в”Ђв”Ђ depthLabel в”Ђв”Ђ
        try {
            Function<Integer, String> depthLabel =
                depth -> { if (depth > 100) return "deep"; else return "shallow"; };
            check("depthLabel(150)", "deep",    depthLabel.apply(150));
            check("depthLabel(50)",  "shallow", depthLabel.apply(50));
            check("depthLabel(100)", "shallow", depthLabel.apply(100));
            check("depthLabel(101)", "deep",    depthLabel.apply(101));
        } catch (Exception e) { fail("depthLabel lambda", e); }

        // в”Ђв”Ђ nameLength в”Ђв”Ђ
        try {
            Function<String, Integer> nameLength = s -> s.length();
            check("nameLength(Coral)",     "5",  String.valueOf(nameLength.apply("Coral")));
            check("nameLength(Sea Breeze)","9",  String.valueOf(nameLength.apply("Sea Breeze")));
            check("nameLength()",          "0",  String.valueOf(nameLength.apply("")));
        } catch (Exception e) { fail("nameLength lambda", e); }

        // в”Ђв”Ђ buildLambdas() runs without NPE в”Ђв”Ђ
        try {
            LambdaExercise.buildLambdas();
            checkBool("buildLambdas() runs without crash", true, true);
        } catch (NullPointerException e) {
            System.out.println("FAIL: buildLambdas() \u2014 a lambda is still null (did you forget a TODO?)");
            failed++;
        } catch (Exception e) { fail("buildLambdas()", e); }

        // в”Ђв”Ђ summary в”Ђв”Ђ
        System.out.println();
        int total = passed + failed;
        System.out.println((passed == total ? "PASS" : "FAIL")
            + ": " + passed + "/" + total + " tests passed");
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void checkBool(String label, boolean expected, boolean actual) {
        if (expected == actual) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e); failed++;
    }
}
